"use strict";parserFactory.register("fanfiction.mugglenet.com",()=>new MuggleNetParser);class MuggleNetParser extends Parser{constructor(){super()}getChapterUrls(e){let t=this.getBaseUrl(e),r=[...e.querySelectorAll("select[name='chapter'] option")];return 0===r.length?Promise.resolve(this.singleChapterStory(t,e)):Promise.resolve(r.map(e=>this.optionToChapterInfo(t,e)))}optionToChapterInfo(e,t){let r=t.getAttribute("value"),l=e.indexOf("chapter=")+8;return{sourceUrl:e.slice(0,l)+r,title:t.innerText}}findContent(e){return e.querySelector("div#story")}extractTextFromPageTitle(e,t){let r="<unknown>",l=[...e.querySelectorAll("div#pagetitle a")];return t<l.length&&(r=l[t].textContent.trim()),r}extractTitleImpl(e){return this.extractTextFromPageTitle(e,0)}extractAuthor(e){return this.extractTextFromPageTitle(e,1)}}